mapper.select:
select DATE_FORMAT(bydate,'%y-%m') posted_date,sum(spend) amount,m.currency
from t_amz_advert_report adv
left join t_amazon_auth a on a.sellerid=adv.sellerid
left join t_marketplace m on m.marketplaceId=adv.marketplaceid
where adv.bydate>=#{fromDate,jdbcType=CHAR}
	and adv.bydate<=#{endDate,jdbcType=CHAR}

	and adv.marketplaceid=#{marketplaceid,jdbcType=CHAR}


	and a.groupid=#{groupid,jdbcType=CHAR}

	and a.shop_id=#{shopid,jdbcType=CHAR}
group by DATE_FORMAT(bydate,'%y-%m'),m.currency
order by DATE_FORMAT(bydate,'%y-%m') asc

select max(concat(right(CAST(m.year AS SIGNED),2),'-', case when m.month<10 then '0' else '' end ,m.month)) posted_date,
	max(p.name) name ,max(m.rec -m.pay) amount
from t_erp_fin_type_journalmonthly m
LEFT JOIN t_erp_fin_account a ON a.id=m.acct
left join t_erp_fin_project p on m.projectid=p.id
where a.shopid=#{shopid,jdbcType=CHAR}

	and concat(m.year,'-',case when m.month<10 then '0' else '' end ,m.month,'-01')>=#{fromDate,jdbcType=CHAR}
	and concat(m.year,'-',case when m.month<10 then '0' else '' end ,m.month,'-01')<=#{endDate,jdbcType=CHAR}


	and concat(m.year,'-',case when m.month<10 then '0' else '' end ,m.month,'-01')>=#{setfromDate,jdbcType=CHAR}
	and concat(m.year,'-',case when m.month<10 then '0' else '' end ,m.month,'-01')<=#{setendDate,jdbcType=CHAR}

group by m.year,m.month,p.id

		select t.amount_description amounttype,max(t.currency) currency ,sum(t.amount) amount
		from t_amz_settlement_summary_month t
		left join t_amazon_auth a on a.id=t.amazonAuthId

			left join t_amz_settlement_acc_report acc on acc.settlement_id=t.settlementid

		where 1=1

		  and t.posted_date>=#{fromDate,jdbcType=CHAR}
		  and t.posted_date<=#{endDate,jdbcType=CHAR}


  	         and acc.deposit_date>=#{fromDate,jdbcType=CHAR}
  	         and acc.deposit_date<=#{endDate,jdbcType=CHAR}
  	         and t.posted_date>=#{setfromDate,jdbcType=CHAR}
		     and t.posted_date<=#{setendDate,jdbcType=CHAR}

			and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR}



			and a.shop_id=#{shopid,jdbcType=CHAR}
			and ((transaction_type='Order' and amount_description!='Principal'
				and amount_description not like 'FBA%' and amount_description not like 'Commission%' ) or amount_type='FBA Inventory Reimbursement')

			and t.marketplace_name=#{marketplace_name,jdbcType=CHAR}


			and a.groupid=#{groupid,jdbcType=CHAR}

		group by t.amount_description,t.marketplace_name

		select t.amount_description amounttype,t.currency ,sum(t.amount) amount
		from t_amz_settlement_summary_month t
		left join t_amazon_auth a on a.id=t.amazonAuthId

			left join t_amz_settlement_acc_report acc on acc.settlement_id=t.settlementid

		where 1=1

		  and t.posted_date>=#{fromDate,jdbcType=CHAR}
		  and t.posted_date<=#{endDate,jdbcType=CHAR}


  	         and acc.deposit_date>=#{fromDate,jdbcType=CHAR}
  	         and acc.deposit_date<=#{endDate,jdbcType=CHAR}
  	         and t.posted_date>=#{setfromDate,jdbcType=CHAR}
		     and t.posted_date<=#{setendDate,jdbcType=CHAR}

			  and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR}


			and a.shop_id=#{shopid,jdbcType=CHAR}
			AND ( t.transaction_type!='Order' and t.transaction_type!='Refund' and t.amount_type!='Cost of Advertising' 
				and t.amount_type!='FBA Inventory Reimbursement' or ( t.transaction_type='Order' and t.amount_description='Principal'
				and t.amount_type!='ItemPrice' )
			)

			and t.marketplace_name=#{marketplace_name,jdbcType=CHAR}


			and a.groupid=#{groupid,jdbcType=CHAR}

		group by t.amount_description,t.marketplace_name

SELECT m.amazonAuthId, m.marketplace_name, m.transaction_type, m.amount_type, m.amount_description, max(transaction_type.cname) transaction_typename, max(amount_type.cname) amount_typename, max(amount_description.cname) amount_descriptionname, sum( case when m.transaction_type='Order' and m.amount_type='ItemPrice' and m.amount_description='Principal' then m.quantity_orders ELSE 0 END
) orders, sum( case when m.transaction_type='Refund' and m.amount_type='ItemPrice' and m.amount_description='Principal' then m.quantity_orders ELSE 0 END
) refundOrders, m.currency, case when count(nosku.transaction_type) >0 then 1 ELSE 0 END isnosku, sum(m.amount) amount from t_amz_settlement_summary_month m LEFT JOIN t_amz_settlement_amount_description transaction_type ON transaction_type.ename=m.transaction_type LEFT JOIN t_amz_settlement_amount_description amount_type ON amount_type.ename=m.amount_type LEFT JOIN t_amz_settlement_amount_description amount_description ON amount_description.ename=m.amount_description LEFT JOIN t_amz_settlement_amount_type_nonsku nosku ON nosku.transaction_type=m.transaction_type AND nosku.amount_type=m.amount_type AND nosku.amount_description=case when nosku.amount_description='*' then nosku.amount_description ELSE m.amount_description end LEFT JOIN t_amazon_auth a ON a.id=m.amazonAuthId LEFT JOIN t_amazon_group g ON g.id=a.groupid
left join t_amz_settlement_acc_report acc on acc.settlement_id=m.settlementid
where 1=1
and m.posted_date>=#{fromDate,jdbcType=CHAR} and m.posted_date<=#{endDate,jdbcType=CHAR}
and acc.deposit_date>=#{fromDate,jdbcType=CHAR} and acc.deposit_date<=#{endDate,jdbcType=CHAR}
and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR}
AND g.shopid=#{shopid,jdbcType=CHAR}
and g.id=#{groupid,jdbcType=CHAR}
AND m.marketplace_name=#{marketplace_name,jdbcType=CHAR}
AND m.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}
GROUP BY m.amazonAuthId,m.marketplace_name,m.transaction_type,m.amount_type,m.amount_description,m.currency

 SELECT SUM(r.total_amount)*-1
 FROM t_amz_settlement_acc_report r
 WHERE  r.amazonauthid=#{amazonauthid,jdbcType=CHAR}
   AND  r.marketplace_name=#{marketplace_name,jdbcType=CHAR}
   and
	 ( (r.deposit_date>=#{fromDate,jdbcType=CHAR}
		 and
		r.deposit_date<#{endDate,jdbcType=CHAR}
		   )
		 or
	   ( r.settlement_start_date>=#{fromDate,jdbcType=CHAR}
		   AND
		 r.settlement_end_date<#{endDate,jdbcType=CHAR}
		   )
		 )

 SELECT SUM(r.total_amount)*-1
 FROM t_amz_settlement_acc_report r
 WHERE
	 r.amazonauthid=#{amazonauthid,jdbcType=CHAR}
   AND  r.marketplace_name=#{marketplace_name,jdbcType=CHAR}
   and
	 ( (r.deposit_date>=#{fromDate,jdbcType=CHAR}
		 and
		r.deposit_date<#{endDate,jdbcType=CHAR}
		   )
		 or
	   ( r.settlement_start_date>=#{fromDate,jdbcType=CHAR}
		   AND
		 r.settlement_end_date<#{endDate,jdbcType=CHAR}
		   )
		 )
   and r.invalid=1
